template.css:
.cribl-alert-widget { padding: 20px; }
.widget-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
.summary-cards { display: flex; gap: 16px; margin-bottom: 24px; }
.summary-cards .card { padding: 16px 24px; border-radius: 8px; text-align: center; min-width: 100px; }
.summary-cards .card .count { display: block; font-size: 28px; font-weight: bold; }
.summary-cards .card .label { font-size: 12px; text-transform: uppercase; color: #666; }
.card.critical { background: #ffebee; border: 1px solid #ef5350; }
.card.critical .count { color: #c62828; }
.card.high { background: #fff3e0; border: 1px solid #ff9800; }
.card.high .count { color: #e65100; }
.card.medium { background: #fff8e1; border: 1px solid #ffc107; }
.card.medium .count { color: #f57f17; }
.card.resolved { background: #e8f5e9; border: 1px solid #66bb6a; }
.card.resolved .count { color: #2e7d32; }
.score-badge { padding: 2px 8px; border-radius: 12px; font-size: 12px; font-weight: bold; }
.score-critical { background: #c62828; color: white; }
.score-standard { background: #f57c00; color: white; }
.score-low { background: #fbc02d; color: #333; }
.score-informational { background: #e0e0e0; color: #666; }
.critical-row { background: #fff8f8; }

server_script:
(function() {
    var userGroups = gs.getUser().getMyGroups();
    var summary = { open_cases: 0, critical: 0, high: 0, medium: 0, resolved_today: 0 };

    var countGr = new GlideAggregate('x_cribl_alert_case');
    countGr.addQuery('state', '!=', 7);
    countGr.addQuery('state', '!=', 8);
    countGr.addAggregate('COUNT');
    countGr.addAggregate('COUNT', 'severity');
    countGr.groupBy('severity');
    countGr.query();
    while (countGr.next()) {
        var sev = countGr.getValue('severity');
        var count = parseInt(countGr.getAggregate('COUNT', 'severity'));
        summary.open_cases += count;
        if (sev == '1') summary.critical = count;
        else if (sev == '2') summary.high = count;
        else if (sev == '3') summary.medium = count;
    }

    var resolvedGr = new GlideAggregate('x_cribl_alert_case');
    resolvedGr.addQuery('state', 6);
    resolvedGr.addQuery('sys_updated_on', '>=', gs.beginningOfToday());
    resolvedGr.addAggregate('COUNT');
    resolvedGr.query();
    if (resolvedGr.next()) {
        summary.resolved_today = parseInt(resolvedGr.getAggregate('COUNT'));
    }

    var cases = [];
    var caseGr = new GlideRecord('x_cribl_alert_case');
    caseGr.addQuery('state', '!=', 7);
    caseGr.addQuery('state', '!=', 8);
    caseGr.addQuery('assignment_group', 'IN', userGroups.toString());
    caseGr.orderByDesc('impact_score');
    caseGr.setLimit(20);
    caseGr.query();
    while (caseGr.next()) {
        var scorer = new x_cribl_alert_intel.ImpactScorer();
        cases.push({
            sys_id: caseGr.getUniqueValue(),
            number: caseGr.getValue('number'),
            short_description: caseGr.getValue('short_description'),
            impact_score: parseInt(caseGr.getValue('impact_score')),
            score_band: scorer.getScoreBand(parseInt(caseGr.getValue('impact_score'))),
            source_type: caseGr.getValue('source_type'),
            state_display: caseGr.getDisplayValue('state'),
            last_seen_display: caseGr.getDisplayValue('last_seen')
        });
    }

    data.summary = summary;
    data.cases = cases;
})();

client_script:
function($scope) {
    var c = this;
    c.statusColor = c.data.summary.critical > 0 ? 'danger' : (c.data.summary.open_cases > 20 ? 'warning' : 'success');
}
